SELECT AVG(population) AS average_population
FROM geographic_regions
WHERE gdp > (SELECT AVG(gdp) FROM geographic_regions WHERE geo_id = 1);

SELECT region_name, country
FROM geographic_regions
WHERE geo_id > 5;

SELECT df.file_path
FROM data_files AS df
WHERE df.upload_date >= date('now', '-1 month');

SELECT geo_id
FROM geographic_regions
WHERE geo_id NOT IN (SELECT geo_id FROM economic_data);

SELECT reliability_score, source_id
FROM data_sources
WHERE last_audit_date = (SELECT MAX(last_audit_date) FROM data_sources);
